codeExercises.solution:
const mongoose = require('mongoose');

const blogPostSchema = new mongoose.Schema({
  title: {
    type: String,
    required: true
  },
  body: {
    type: String,
    required: true
  },
  status: {
    type: String,
    enum: ['draft', 'published', 'archived'],
    default: 'draft'
  },
  tags: [String]
});

const BlogPost = mongoose.model('BlogPost', blogPostSchema);

module.exports = BlogPost;

