codeExercises.solution:
const mongoose = require('mongoose');

const columnSchema = new mongoose.Schema({
  boardId: {
    type: mongoose.Schema.Types.ObjectId,
    ref: 'Board',
    required: true
  },
  title: {
    type: String,
    required: true,
    minlength: 3,
    maxlength: 50,
    trim: true
  },
  cardOrderIds: [{
    type: mongoose.Schema.Types.ObjectId,
    ref: 'Card',
    default: []
  }]
}, {
  timestamps: true
});

const Column = mongoose.model('Column', columnSchema);

module.exports = Column;
